record_types.code:
type Can_Addr_Type is record
   rx_id : aliased Can_Frame.Can_Id_Type;
   tx_id : aliased Can_Frame.Can_Id_Type;
end record;

type Ifreq is record
   Ifr_Name  : Ifr_Name_Array;
   Ifr_Index : Interfaces.C.Unsigned;
   Unused    : Interfaces.C.Char_Array (1 .. 20);
end record;

type kernel_sockaddr_storage is record
   ss_family : aliased Interfaces.C.unsigned_short;
   data      : aliased data_array;
end record;

type sockaddr_can is record
   can_family  : aliased Interfaces.C.Unsigned_Short;
   can_ifindex : aliased Interfaces.C.Unsigned;
   can_addr    : aliased Can_Addr_Type;
end record;
